import time
from typing import List, Dict, Optional
import numpy as np

# Global variables for timeout handling
_TIMEOUT_SEC = 120
_START_TIME = time.time()

class Operation:
    def __init__(self, job_id: int, op_id: int, machine: int, duration: int):
        self.job_id = job_id
        self.op_id = op_id
        self.machine = machine
        self.duration = duration
        self.start = 0
        self.end = 0

def solve(jobs: List[List[Dict]]) -> List[List[Dict]]:
    global _START_TIME

    # Parse input into operations
    operations = []
    for job_id, job in enumerate(jobs):
        for op_id, op in enumerate(job):
            operations.append(Operation(job_id, op_id, op["machine"], op["duration"]))

    num_jobs = len(jobs)
    num_ops_per_job = len(jobs[0]) if num_jobs > 0 else 0
    num_machines = max(op["machine"] for job in jobs for op in job) + 1 if num_jobs > 0 else 0

    # Initialize domains: possible start times for each operation
    domains = {}
    for op in operations:
        domains[op] = list(range(0, 10000))  # Initial large domain

    # Track best solution found
    best_solution = None
    best_makespan = float('inf')

    def get_current_time():
        return time.time() - _START_TIME

    def is_timeout():
        return get_current_time() > 0.8 * _TIMEOUT_SEC

    def forward_check(op: Operation, start_time: int) -> bool:
        """Check if assigning start_time to op is feasible with current domains."""
        # Update operation's start and end
        op.start = start_time
        op.end = start_time + op.duration

        # Check machine conflict
        for other_op in operations:
            if other_op == op:
                continue
            if other_op.machine == op.machine:
                if other_op.start <= start_time < other_op.end or start_time <= other_op.start < op.end:
                    return False

        # Check job precedence
        # Previous operation in the same job must finish before this one starts
        prev_op = next((o for o in operations if o.job_id == op.job_id and o.op_id == op.op_id - 1), None)
        if prev_op and prev_op.end > start_time:
            return False

        return True

    def constraint_propagation(op: Operation, start_time: int):
        """Propagate constraints after assigning start_time to op."""
        # Update domains for operations on the same machine
        for other_op in operations:
            if other_op == op or other_op.machine != op.machine:
                continue
            # Remove start times that would overlap with op
            new_domain = []
            for t in domains[other_op]:
                if t + other_op.duration <= op.start or t >= op.end:
                    new_domain.append(t)
            domains[other_op] = new_domain
            if not domains[other_op]:
                return False

        # Update domains for next operation in the same job
        next_op = next((o for o in operations if o.job_id == op.job_id and o.op_id == op.op_id + 1), None)
        if next_op:
            new_domain = [t for t in domains[next_op] if t >= op.end]
            domains[next_op] = new_domain
            if not domains[next_op]:
                return False

        return True

    def backtrack(assigned_ops: List[Operation]) -> Optional[List[List[Dict]]]:
        nonlocal best_solution, best_makespan

        if is_timeout():
            return None

        # All operations assigned
        if len(assigned_ops) == len(operations):
            current_makespan = max(op.end for op in operations)
            if current_makespan < best_makespan:
                best_makespan = current_makespan
                best_solution = [[{
                    "machine": op.machine,
                    "duration": op.duration,
                    "start": op.start
                } for op in operations if op.job_id == job_id] for job_id in range(num_jobs)]
            return best_solution

        # Select next operation to assign (minimum remaining values heuristic)
        unassigned_ops = [op for op in operations if op not in assigned_ops]
        if not unassigned_ops:
            return None

        # Choose operation with smallest domain
        next_op = min(unassigned_ops, key=lambda op: len(domains[op]))

        # Try each possible start time in domain
        for start_time in domains[next_op]:
            if forward_check(next_op, start_time):
                # Save current domains for backtracking
                saved_domains = {op: list(d) for op, d in domains.items()}

                if constraint_propagation(next_op, start_time):
                    assigned_ops.append(next_op)
                    result = backtrack(assigned_ops)
                    if result is not None:
                        return result
                    assigned_ops.remove(next_op)

                # Restore domains
                domains.update(saved_domains)

        return None

    # Initial constraint propagation
    for op in operations:
        # Previous operation in job must finish before this one starts
        prev_op = next((o for o in operations if o.job_id == op.job_id and o.op_id == op.op_id - 1), None)
        if prev_op:
            domains[op] = [t for t in domains[op] if t >= prev_op.end]

    # Start backtracking
    backtrack([])

    # If no solution found, return a simple greedy solution
    if best_solution is None:
        best_solution = greedy_schedule(jobs)

    return best_solution

def greedy_schedule(jobs: List[List[Dict]]) -> List[List[Dict]]:
    """Fallback greedy scheduler if constraint programming fails."""
    num_jobs = len(jobs)
    machine_availability = {}
    job_last_finish = [0] * num_jobs

    # Initialize machine availability
    for job in jobs:
        for op in job:
            machine = op["machine"]
            if machine not in machine_availability:
                machine_availability[machine] = 0

    scheduled_jobs = [[] for _ in range(num_jobs)]

    for job_id in range(num_jobs):
        for op in jobs[job_id]:
            machine = op["machine"]
            duration = op["duration"]

            # Start time is max of machine availability and previous operation in job
            start = max(machine_availability[machine], job_last_finish[job_id])

            scheduled_op = {
                "machine": machine,
                "duration": duration,
                "start": start
            }
            scheduled_jobs[job_id].append(scheduled_op)

            # Update machine and job availability
            machine_availability[machine] = start + duration
            job_last_finish[job_id] = start + duration

    return scheduled_jobs
